parameters.jsonBody:
={{ JSON.stringify({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  system: "You analyze project inquiry forms submitted to a freelance automation developer. Extract and assess the lead. Respond with ONLY a valid JSON object, no markdown fences, no preamble, with EXACTLY these keys:
- lead_quality: one of 'hot' (clear need + budget + timeline), 'warm' (has need but vague budget/timeline), 'cold' (too vague or very low budget)
- project_type: one of 'workflow_automation', 'ai_agent', 'rag_chatbot', 'data_pipeline', 'integration', 'other'
- budget_usd: extract numeric estimate if mentioned, or 0 if not mentioned
- timeline: one of 'urgent' (< 2 weeks), 'normal' (2-8 weeks), 'flexible' (no deadline mentioned)
- summary: 1-2 sentence summary of what they need
- suggested_action: one specific next step the freelancer should take (e.g. 'Schedule a discovery call to clarify scope', 'Send portfolio of similar RAG projects', 'Ask for budget range before proceeding')
Output nothing except the JSON object.",
  messages: [{
    role: 'user',
    content: `Analyze this project inquiry:

Name: ${$json['Full Name']}
Email: ${$json['Email']}
Company: ${$json['Company'] || 'Not provided'}
Project Description: ${$json['Project Description']}
Budget: ${$json['Budget (USD)'] || 'Not mentioned'}`
  }]
}) }}

parameters.jsCode:
// Parse Claude response + merge with form data
const claudeResponse = $input.first();
const formData = $('Project Inquiry Form').first();

let raw = '';
try {
  raw = claudeResponse.json.content[0].text;
} catch (e) {
  throw new Error('Anthropic response unexpected: ' + JSON.stringify(claudeResponse.json).slice(0, 300));
}

const clean = raw.replace(/```json/gi, '').replace(/```/g, '').trim();

let ai;
try {
  ai = JSON.parse(clean);
} catch (e) {
  ai = { lead_quality: 'warm', project_type: 'other', budget_usd: 0, timeline: 'flexible', summary: clean.slice(0, 200), suggested_action: 'Review manually' };
}

return [{
  json: {
    // Form fields
    submitted_at: new Date().toISOString(),
    full_name: formData.json['Full Name'] || '',
    email: formData.json['Email'] || '',
    company: formData.json['Company'] || '',
    project_description: formData.json['Project Description'] || '',
    budget_raw: formData.json['Budget (USD)'] || '',
    // AI analysis
    lead_quality: ai.lead_quality || 'warm',
    project_type: ai.project_type || 'other',
    budget_usd: ai.budget_usd || 0,
    timeline: ai.timeline || 'flexible',
    summary: ai.summary || '',
    suggested_action: ai.suggested_action || ''
  }
}];

